function BrokenTripleIncrement() {
  const [count, setCount] = useState(0);

  function handleClick() {
    // count is 0 for the entire handler — a frozen snapshot
    setCount(count + 1); // schedules: replace with 0+1 = 1
    setCount(count + 1); // schedules: replace with 0+1 = 1
    setCount(count + 1); // schedules: replace with 0+1 = 1
    // After render: count = 1, not 3
  }

  return <button onClick={handleClick}>+3 (broken): {count}</button>;
}

function WorkingTripleIncrement() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(prev => prev + 1); // queues: prev=0 → 1
    setCount(prev => prev + 1); // queues: prev=1 → 2
    setCount(prev => prev + 1); // queues: prev=2 → 3
    // After render: count = 3
  }

  return <button onClick={handleClick}>+3 (correct): {count}</button>;
}

