setCount(n => n * 2);  // queue: [10, n=>n*2]      pending = 20
setCount(n => n - 3);  // queue: [10, n=>n*2, n=>n-3] pending = 17
// Re-render with count = 17

function TodoList() {
  const [todos, setTodos] = useState([]);

  function addTodo(text) {
    // prev is the latest pending array, not the snapshot
    setTodos(prev => [...prev, { id: Date.now(), text, done: false }]);
  }

  function toggleTodo(id) {
    setTodos(prev =>
      prev.map(todo =>
        todo.id === id ? { ...todo, done: !todo.done } : todo
      )
    );
  }

  function removeTodo(id) {
    setTodos(prev => prev.filter(todo => todo.id !== id));
  }

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          <span
            style={{ textDecoration: todo.done ? 'line-through' : 'none' }}
            onClick={() => toggleTodo(todo.id)}
          >
            {todo.text}
          </span>
          <button onClick={() => removeTodo(todo.id)}>Remove</button>
        </li>
      ))}
      <button onClick={() => addTodo('New task')}>Add</button>
    </ul>
  );
}

// Object state with functional update
function UserProfile() {
  const [user, setUser] = useState({ name: '', age: 0, active: true });

  function updateName(name) {
    // Spread the previous object, then override the field
    setUser(prev => ({ ...prev, name }));
  }

  function deactivate() {
    setUser(prev => ({ ...prev, active: false }));
  }

  return (
    <div>
      <input value={user.name} onChange={e => updateName(e.target.value)} />
      <button onClick={deactivate}>Deactivate</button>
      <p>{user.active ? 'Active' : 'Inactive'}</p>
    </div>
  );
}

function PollingCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      // WRONG: count is frozen at the snapshot from the render
      // that ran useEffect. It will always be 0.
      // setCount(count + 1);

      // CORRECT: prev is always the latest committed value
      setCount(prev => prev + 1);
    }, 1000);

    return () => clearInterval(id);
  }, []); // empty deps — intentional; functional form is safe here

  return <p>Seconds: {count}</p>;
}

function NotificationFeed() {
  const [notifications, setNotifications] = useState([]);

  async function fetchNew() {
    const fresh = await getLatestNotifications();
    // Functional form: prepend fresh items regardless of what arrived
    // since the fetch started
    setNotifications(prev => [...fresh, ...prev]);
  }

  return (
    <>
      <button onClick={fetchNew}>Refresh</button>
      <ul>{notifications.map(n => <li key={n.id}>{n.text}</li>)}</ul>
    </>
  );
}

