setItems(prev => {
  prev.push(newItem); // mutation — don't do this
  return prev;
});

setCount(prev => {
  console.log('side effect'); // impure — Strict Mode will expose this
  return prev + 1;
});

function LikeButton({ postId }) {
  const [likes, setLikes] = useState(0);

  async function handleLike() {
    // Optimistically increment
    setLikes(prev => prev + 1);

    try {
      await saveLike(postId);
    } catch {
      // Roll back exactly one increment
      setLikes(prev => prev - 1);
    }
  }

  return <button onClick={handleLike}>♥ {likes}</button>;
}

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('triple increment chains correctly', async () => {
  const user = userEvent.setup();
  render(<WorkingTripleIncrement />);

  const btn = screen.getByRole('button');
  await user.click(btn);
  expect(btn).toHaveTextContent('+3 (correct): 3');

  await user.click(btn);
  expect(btn).toHaveTextContent('+3 (correct): 6');
});

function useCounter(initial = 0) {
  const [count, setCount] = useState(initial);

  const increment = useCallback(() => setCount(c => c + 1), []);
  const decrement = useCallback(() => setCount(c => c - 1), []);
  const reset     = useCallback(() => setCount(initial), [initial]);
  const addBy     = useCallback(n => setCount(c => c + n), []);

  return { count, increment, decrement, reset, addBy };
}

// Usage
function ScoreBoard() {
  const { count, increment, addBy, reset } = useCounter(0);
  return (
    <div>
      <p>Score: {count}</p>
      <button onClick={increment}>+1</button>
      <button onClick={() => addBy(10)}>+10</button>
      <button onClick={reset}>Reset</button>
    </div>
  );
}

// Unstable: handleAdd changes on every count change
const handleAdd = useCallback(() => {
  setCount(count + 1); // reads count from closure
}, [count]); // must list count as dep

// Stable: handleAdd is created once and never re-created
const handleAdd = useCallback(() => {
  setCount(c => c + 1); // reads nothing from closure
}, []); // no deps needed

const INITIAL = {
  user: { name: 'Alice', address: { city: 'London', zip: 'EC1' } },
  settings: { theme: 'light', lang: 'en' },
};

function Profile() {
  const [data, setData] = useState(INITIAL);

  function updateCity(city) {
    setData(prev => ({
      ...prev,                           // keep settings
      user: {
        ...prev.user,                   // keep name
        address: { ...prev.user.address, city }, // update city only
      },
    }));
  }

  function toggleTheme() {
    setData(prev => ({
      ...prev,
      settings: {
        ...prev.settings,
        theme: prev.settings.theme === 'light' ? 'dark' : 'light',
      },
    }));
  }

  return (
    <div>
      <p>{data.user.name} — {data.user.address.city}</p>
      <p>Theme: {data.settings.theme}</p>
      <button onClick={() => updateCity('Paris')}>Move to Paris</button>
      <button onClick={toggleTheme}>Toggle theme</button>
    </div>
  );
}

// Pure state transition functions — no React dependency
export const addItem = item => prev => [...prev, item];
export const removeItem = id => prev => prev.filter(i => i.id !== id);
export const toggleItem = id => prev =>
  prev.map(i => (i.id === id ? { ...i, done: !i.done } : i));

// Unit tests for the logic — no render needed
test('addItem appends to list', () => {
  const result = addItem({ id: 1, text: 'Buy milk', done: false })([]);
  expect(result).toEqual([{ id: 1, text: 'Buy milk', done: false }]);
});

// In the component, just call them
function Tasks() {
  const [items, setItems] = useState([]);
  return (
    <ul>
      {items.map(i => (
        <li key={i.id}>
          <span onClick={() => setItems(toggleItem(i.id))}>{i.text}</span>
          <button onClick={() => setItems(removeItem(i.id))}>x</button>
        </li>
      ))}
      <button onClick={() => setItems(addItem({ id: Date.now(), text: 'New', done: false }))}>
        Add
      </button>
    </ul>
  );
}
